#include <fstream>
#include <vector>
#include <algorithm>
using namespace std;

// Get number of apparitions of a letter in a word
int getNoOfApp(const string& word, char letter) {
	int app = 0;

	for (int i = 0; i < word.size(); i++)
		app += (word[i] == letter);

	return app;
}

int main() {
	ifstream fin("statistics.in");
	ofstream fout("statistics.out");

	int n, maxNoOfWords = 0;
	vector<string> words;

	fin >> n;

	for (int i = 0; i < n; i++) {
		string word;

		fin >> word;
		words.push_back(word);
	}

	// Try each letter
	for (char c = 'a'; c <= 'z'; c++) {
		int currMaxNoWords = 0, app = 0, total = 0;
		vector<pair<int, int>> v;

		for (int j = 0; j < n; j++) {
			int currApp = getNoOfApp(words[j], c);

			if (currApp > words[j].size() / 2) {
				app += currApp;
				total += words[j].size();
				currMaxNoWords++;
			} else {
				v.push_back({currApp, words[j].size()});
			}
		}

		if (!currMaxNoWords)
			continue;

		// Sort number of apparitions accordingly
		sort(v.begin(), v.end(), [&](const auto& pair1, const auto& pair2) {
			int a1 = pair1.first, b1 = pair1.second;
			int a2 = pair2.first, b2 = pair2.second;

			return (2 * a1 - b1) > (2 * a2 - b2);
		});

		// Greedely take best results
		int index = 0;

		while (index < v.size()) {
			app += v[index].first;
			total += v[index].second;

			if (app > total / 2)
				currMaxNoWords++;
			else
				break;

			index++;
		}

		maxNoOfWords = max(maxNoOfWords, currMaxNoWords);
	}

	if (!maxNoOfWords)
		fout << -1 << "\n";
	else
		fout << maxNoOfWords << "\n";

	fin.close();
	fout.close();

	return 0;
}

import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.Arrays;
import java.util.Collections;

public class Statistics {

	// citesc din fisier n si cele n string-uri
	private String[] readInput() {
		String[] strings = new String[0];

		try {
			String path = "../statistics.in";
			BufferedReader bufferedReader = new BufferedReader(
					new FileReader(path));

			String line = bufferedReader.readLine();
			int n = Integer.parseInt(line);
			strings = new String[n];

			for (int j = 0; j < n; j++) {
				line = bufferedReader.readLine();
				strings[j] = line;
			}

			bufferedReader.close();

		} catch (IOException e) {
			e.printStackTrace();
		}

		return strings;
	}

	// afisez in fisier rezultatul
	private void writeOutput(int result) {
		try {
			String path = "../statistics.out";
			PrintWriter pw = new PrintWriter(new File(path));
			pw.printf("%d\n", result);
			pw.close();
		} catch (IOException e) {
			throw new RuntimeException(e);
		}
	}

	/* calculez diferenta dintre numarul de aparitii dintre caracterul
	 * primit ca parametru si restul caracterelor stringului
	 */
	private int numOfApp(String str, char ch) {
		int numOfCh = 0, numOfOthers = 0;

		for (int i = 0; i < str.length(); i++) {
			if (str.charAt(i) == ch) {
				numOfCh++;
			} else {
				numOfOthers++;
			}
		}

		return (numOfCh - numOfOthers);
	}

	private int maximumNumberOfStrings(String[] strings, int n) {
		int res = 0;
		// parcurg fiecare cifra a alfabetului englez
		for (char c = 'a'; c <= 'z'; c++) {
			Integer[] diff = new Integer[n];

			for (int i = 0; i < n; i++) {
				diff[i] = numOfApp(strings[i], c);
			}

			Arrays.sort(diff);
			Collections.reverse(Arrays.asList(diff));

			int aux = 0, count = 0;

			for (int i = 0; i < n; i++) {
				aux = aux + diff[i];
				if (aux > 0) {
					count++;
				}
			}

			res = Math.max(count, res);
		}

		if (res == 0) {
			return -1;
		}

		return res;
	}

	public static void main(String[] args) {
		Statistics statistics = new Statistics();

		String[] strings = statistics.readInput();

		statistics.writeOutput(statistics.maximumNumberOfStrings(strings, strings.length));

	}
}
